#!/usr/bin/env python3
"""
Universal x-gnosis standard-service harness.

This compatibility lane gives every polyglot language a basic HTTP server
surface even when Ditto does not recognize a higher-level framework. The
target program runs once per request and receives the request envelope via
environment variables:

- XGNOSIS_HTTP_METHOD
- XGNOSIS_HTTP_PATH
- XGNOSIS_HTTP_QUERY
- XGNOSIS_HTTP_URL
- XGNOSIS_HTTP_HEADERS_JSON
- XGNOSIS_HTTP_BODY_BASE64
- XGNOSIS_HTTP_BODY_UTF8 (when the body decodes cleanly)
- XGNOSIS_HTTP_REQUEST_JSON
- XGNOSIS_HTTP_REQUEST_BASE64

Programs can answer in one of three ways:
- print a full compatibility response: {"matched": true, "response": {...}}
- print a response object: {"status": 201, "headers": {...}, "body": ...}
- print plain text or JSON, which is wrapped into a 200 response
"""

from __future__ import annotations

import base64
import json
import os
import re
import shlex
import shutil
import subprocess
import sys
import tempfile
from pathlib import Path
from typing import Any


DEFAULT_LANGUAGE_COMMANDS: dict[str, list[str]] = {
    "python": ["python3"],
    "javascript": ["node"],
    "typescript": ["node", "--import", "tsx"],
    "go": ["go", "run"],
    "ruby": ["ruby"],
    "php": ["php"],
    "lua": ["lua"],
    "elixir": ["elixir"],
    "bash": ["bash"],
    "shell": ["sh"],
}


def write_response(response: dict[str, Any]) -> None:
    sys.stdout.write(json.dumps(response))


def error_response(message: str, stdout: str = "", stderr: str = "") -> None:
    write_response(
        {
            "status": "error",
            "value": message,
            "stdout": stdout,
            "stderr": stderr,
        }
    )


def read_request() -> dict[str, Any]:
    raw_input = sys.stdin.read()
    if not raw_input.strip():
        error_response("empty input")
        raise SystemExit(0)

    try:
        return json.loads(raw_input)
    except json.JSONDecodeError as error:
        error_response(f"invalid JSON input: {error}")
        raise SystemExit(0)


def resolve_command(language: str) -> list[str]:
    env_key = f"GNODE_{language.upper()}_CMD"
    override = os.environ.get(env_key)
    if override:
        return shlex.split(override)
    return DEFAULT_LANGUAGE_COMMANDS.get(language, [])


def decode_base64(value: str) -> bytes:
    try:
        return base64.b64decode(value)
    except Exception:
        return b""


def build_script_service_env(http_request: dict[str, Any]) -> dict[str, str]:
    env = os.environ.copy()
    body = http_request.get("body") or {}
    body_base64 = (
        body.get("value", "")
        if body.get("encoding") == "base64" and isinstance(body.get("value"), str)
        else ""
    )
    request_json = json.dumps(http_request, separators=(",", ":"))
    method = str(http_request.get("method", "GET")).upper()
    path = str(http_request.get("path", "/"))
    query = str(http_request.get("query") or "")
    url = f"{path}{query}" if query else path
    headers = json.dumps(http_request.get("headers") or {}, separators=(",", ":"))

    env.update(
        {
            "XGNOSIS_SCRIPT_SERVICE": "1",
            "XGNOSIS_HTTP_METHOD": method,
            "XGNOSIS_HTTP_PATH": path,
            "XGNOSIS_HTTP_QUERY": query,
            "XGNOSIS_HTTP_URL": url,
            "XGNOSIS_HTTP_HEADERS_JSON": headers,
            "XGNOSIS_HTTP_BODY_BASE64": body_base64,
            "XGNOSIS_HTTP_REQUEST_JSON": request_json,
            "XGNOSIS_HTTP_REQUEST_BASE64": base64.b64encode(
                request_json.encode("utf-8")
            ).decode("ascii"),
        }
    )

    if body_base64:
        body_bytes = decode_base64(body_base64)
        try:
            env["XGNOSIS_HTTP_BODY_UTF8"] = body_bytes.decode("utf-8")
        except UnicodeDecodeError:
            pass

    return env


def decode_output(data: bytes) -> str:
    return data.decode("utf-8", errors="replace")


def run_process(
    args: list[str],
    *,
    cwd: str,
    env: dict[str, str],
) -> tuple[int, str, str]:
    completed = subprocess.run(
        args,
        cwd=cwd,
        env=env,
        check=False,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
    )
    return (
        completed.returncode,
        decode_output(completed.stdout),
        decode_output(completed.stderr),
    )


def run_compiled_binary(
    compile_args: list[str],
    run_args: list[str],
    *,
    cwd: str,
    env: dict[str, str],
) -> tuple[int, str, str]:
    compile_code, compile_stdout, compile_stderr = run_process(
        compile_args, cwd=cwd, env=env
    )
    if compile_code != 0:
        return compile_code, compile_stdout, compile_stderr
    return run_process(run_args, cwd=cwd, env=env)


def extract_java_package(source_path: str) -> str | None:
    try:
        source = Path(source_path).read_text(encoding="utf-8")
    except OSError:
        return None

    match = re.search(r"^\s*package\s+([A-Za-z_][\w.]*)\s*;", source, re.MULTILINE)
    return match.group(1) if match else None


def execute_script_service(
    language: str,
    file_path: str,
    http_request: dict[str, Any],
) -> tuple[int, str, str]:
    absolute_path = str(Path(file_path).resolve())
    source_dir = str(Path(absolute_path).parent)
    env = build_script_service_env(http_request)
    extension = Path(absolute_path).suffix.lower()

    if language in {"python", "javascript", "typescript", "go", "ruby", "php", "lua", "elixir", "bash", "shell"}:
        command = resolve_command(language)
        if not command:
            return 1, "", f"no command configured for language {language}"
        return run_process(command + [absolute_path], cwd=source_dir, env=env)

    if language == "rust":
        compiler = shutil.which("rustc")
        if not compiler:
            return 1, "", "rustc not found"
        with tempfile.TemporaryDirectory(prefix="xgnosis-rust-") as temp_dir:
            binary = str(Path(temp_dir) / "service")
            return run_compiled_binary(
                [compiler, "-o", binary, absolute_path],
                [binary],
                cwd=source_dir,
                env=env,
            )

    if language == "c":
        compiler = shutil.which("cc")
        if not compiler:
            return 1, "", "cc not found"
        with tempfile.TemporaryDirectory(prefix="xgnosis-c-") as temp_dir:
            binary = str(Path(temp_dir) / "service")
            return run_compiled_binary(
                [compiler, "-o", binary, absolute_path, "-lm"],
                [binary],
                cwd=source_dir,
                env=env,
            )

    if language == "cpp":
        compiler = shutil.which("c++")
        if not compiler:
            return 1, "", "c++ not found"
        with tempfile.TemporaryDirectory(prefix="xgnosis-cpp-") as temp_dir:
            binary = str(Path(temp_dir) / "service")
            return run_compiled_binary(
                [compiler, "-std=c++17", "-o", binary, absolute_path],
                [binary],
                cwd=source_dir,
                env=env,
            )

    if language == "java":
        javac = shutil.which("javac")
        java = shutil.which("java")
        if not javac or not java:
            return 1, "", "javac/java not found"
        class_name = Path(absolute_path).stem
        package_name = extract_java_package(absolute_path)
        fqcn = f"{package_name}.{class_name}" if package_name else class_name
        with tempfile.TemporaryDirectory(prefix="xgnosis-java-") as temp_dir:
            compile_args = [javac, "-d", temp_dir, absolute_path]
            run_args = [java, "-cp", temp_dir, fqcn]
            return run_compiled_binary(
                compile_args,
                run_args,
                cwd=source_dir,
                env=env,
            )

    if language == "c_sharp":
        dotnet_script = shutil.which("dotnet-script")
        dotnet = shutil.which("dotnet")
        csc = shutil.which("csc")
        mono = shutil.which("mono")

        if extension == ".csx" and dotnet_script:
            return run_process([dotnet_script, absolute_path], cwd=source_dir, env=env)

        if dotnet:
            with tempfile.TemporaryDirectory(prefix="xgnosis-csharp-") as temp_dir:
                new_result = subprocess.run(
                    [dotnet, "new", "console", "-o", temp_dir, "--force"],
                    cwd=source_dir,
                    env=env,
                    check=False,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                )
                if new_result.returncode != 0:
                    return (
                        new_result.returncode,
                        decode_output(new_result.stdout),
                        decode_output(new_result.stderr),
                    )

                target_source = Path(temp_dir) / "Program.cs"
                target_source.write_text(
                    Path(absolute_path).read_text(encoding="utf-8"),
                    encoding="utf-8",
                )
                return run_process(
                    [dotnet, "run", "--project", temp_dir],
                    cwd=source_dir,
                    env=env,
                )

        if csc:
            with tempfile.TemporaryDirectory(prefix="xgnosis-csharp-") as temp_dir:
                binary = str(Path(temp_dir) / "service.exe")
                compile_code, compile_stdout, compile_stderr = run_process(
                    [csc, f"-out:{binary}", absolute_path],
                    cwd=source_dir,
                    env=env,
                )
                if compile_code != 0:
                    return compile_code, compile_stdout, compile_stderr
                run_args = [mono, binary] if mono else [binary]
                return run_process(run_args, cwd=source_dir, env=env)

        return 1, "", "dotnet/dotnet-script/csc not found"

    if language == "scala":
        scala_cli = shutil.which("scala-cli")
        scala = shutil.which("scala")
        if scala_cli:
            return run_process([scala_cli, "run", absolute_path], cwd=source_dir, env=env)
        if scala:
            return run_process([scala, absolute_path], cwd=source_dir, env=env)
        return 1, "", "scala-cli/scala not found"

    if language == "kotlin":
        kotlin = shutil.which("kotlin")
        kotlinc = shutil.which("kotlinc")
        java = shutil.which("java")
        if extension == ".kts":
            if not kotlin:
                return 1, "", "kotlin not found"
            return run_process([kotlin, absolute_path], cwd=source_dir, env=env)
        if not kotlinc or not java:
            return 1, "", "kotlinc/java not found"
        with tempfile.TemporaryDirectory(prefix="xgnosis-kotlin-") as temp_dir:
            jar_path = str(Path(temp_dir) / "service.jar")
            compile_code, compile_stdout, compile_stderr = run_process(
                [kotlinc, absolute_path, "-include-runtime", "-d", jar_path],
                cwd=source_dir,
                env=env,
            )
            if compile_code != 0:
                return compile_code, compile_stdout, compile_stderr
            return run_process([java, "-jar", jar_path], cwd=source_dir, env=env)

    if language == "swift":
        swift = shutil.which("swift")
        if not swift:
            return 1, "", "swift not found"
        return run_process([swift, absolute_path], cwd=source_dir, env=env)

    if language == "haskell":
        runghc = shutil.which("runghc")
        ghc = shutil.which("ghc")
        if runghc:
            return run_process([runghc, absolute_path], cwd=source_dir, env=env)
        if ghc:
            with tempfile.TemporaryDirectory(prefix="xgnosis-haskell-") as temp_dir:
                binary = str(Path(temp_dir) / "service")
                return run_compiled_binary(
                    [ghc, "-o", binary, absolute_path],
                    [binary],
                    cwd=source_dir,
                    env=env,
                )
        return 1, "", "runghc/ghc not found"

    if language == "ocaml":
        ocaml = shutil.which("ocaml")
        if not ocaml:
            return 1, "", "ocaml not found"
        return run_process([ocaml, absolute_path], cwd=source_dir, env=env)

    if language == "zig":
        zig = shutil.which("zig")
        if not zig:
            return 1, "", "zig not found"
        return run_process([zig, "run", absolute_path], cwd=source_dir, env=env)

    return 1, "", f"unsupported script-service language: {language}"


def normalize_headers(headers: Any) -> dict[str, str]:
    if not isinstance(headers, dict):
        return {}
    return {str(key): str(value) for key, value in headers.items()}


def encode_body_value(
    body: Any,
    headers: dict[str, str],
    *,
    default_content_type: str,
) -> tuple[dict[str, str], dict[str, str] | None]:
    next_headers = dict(headers)

    if body is None:
        return next_headers, None

    if (
        isinstance(body, dict)
        and body.get("encoding") == "base64"
        and isinstance(body.get("value"), str)
    ):
        return next_headers, {"encoding": "base64", "value": body["value"]}

    if isinstance(body, str):
        if "Content-Type" not in next_headers and "content-type" not in next_headers:
            next_headers["Content-Type"] = default_content_type
        return next_headers, {
            "encoding": "base64",
            "value": base64.b64encode(body.encode("utf-8")).decode("ascii"),
        }

    if isinstance(body, (bytes, bytearray)):
        if "Content-Type" not in next_headers and "content-type" not in next_headers:
            next_headers["Content-Type"] = "application/octet-stream"
        return next_headers, {
            "encoding": "base64",
            "value": base64.b64encode(bytes(body)).decode("ascii"),
        }

    if "Content-Type" not in next_headers and "content-type" not in next_headers:
        next_headers["Content-Type"] = default_content_type
    serialized = json.dumps(body)
    return next_headers, {
        "encoding": "base64",
        "value": base64.b64encode(serialized.encode("utf-8")).decode("ascii"),
    }


def normalize_response_payload(payload: Any) -> dict[str, Any]:
    if not isinstance(payload, dict):
        headers, body = encode_body_value(
            payload,
            {},
            default_content_type="application/json; charset=utf-8",
        )
        return {
            "status": 200,
            "headers": headers,
            **({"body": body} if body else {}),
        }

    status = int(payload.get("status", 200))
    headers = normalize_headers(payload.get("headers"))
    headers, body = encode_body_value(
        payload.get("body"),
        headers,
        default_content_type="application/json; charset=utf-8",
    )
    response = {
        "status": status,
        "headers": headers,
    }
    if body:
        response["body"] = body
    return response


def normalize_compatibility_value(payload: Any, raw_stdout: str) -> dict[str, Any]:
    if isinstance(payload, dict) and "matched" in payload:
        if not payload.get("matched"):
            return {"matched": False}
        return {
            "matched": True,
            "response": normalize_response_payload(payload.get("response") or {}),
        }

    if isinstance(payload, dict) and (
        "status" in payload or "headers" in payload or "body" in payload
    ):
        return {
            "matched": True,
            "response": normalize_response_payload(payload),
        }

    if isinstance(payload, str):
        headers, body = encode_body_value(
            payload,
            {},
            default_content_type="text/plain; charset=utf-8",
        )
        return {
            "matched": True,
            "response": {
                "status": 200,
                "headers": headers,
                **({"body": body} if body else {}),
            },
        }

    headers, body = encode_body_value(
        payload,
        {},
        default_content_type="application/json; charset=utf-8",
    )
    return {
        "matched": True,
        "response": {
            "status": 200,
            "headers": headers,
            **({"body": body} if body else {}),
        },
    }


def normalize_stdout_to_compatibility(stdout: str) -> dict[str, Any]:
    stripped = stdout.strip()
    if not stripped:
        return {
            "matched": True,
            "response": {
                "status": 200,
                "headers": {},
            },
        }

    try:
        parsed = json.loads(stripped)
    except json.JSONDecodeError:
        return normalize_compatibility_value(stdout, stdout)

    return normalize_compatibility_value(parsed, stdout)


def main() -> None:
    try:
        request = read_request()

        if request.get("action") == "ping":
            write_response({"status": "ok", "value": "pong", "stdout": "", "stderr": ""})
            return

        compatibility = request.get("compatibility") or {}
        if compatibility.get("family") != "script-service":
            error_response("script-service harness only supports script-service requests")
            return

        language = str(request.get("language") or "")
        file_path = str(request.get("filePath") or "")
        http_request = compatibility.get("request") or {}

        exit_code, stdout, stderr = execute_script_service(language, file_path, http_request)
        if exit_code != 0:
            error_response(
                f"{language} script-service exited with code {exit_code}",
                stdout=stdout,
                stderr=stderr,
            )
            return

        write_response(
            {
                "status": "ok",
                "value": normalize_stdout_to_compatibility(stdout),
                "stdout": stdout,
                "stderr": stderr,
            }
        )
    except SystemExit:
        raise
    except Exception as error:
        error_response(str(error))


if __name__ == "__main__":
    main()
